import type { RelativeAbsolutePosition } from '../types/pointer-events.js';

export function getPercentageFromPixel(
  selectionInPixel: [RelativeAbsolutePosition, RelativeAbsolutePosition],
  width: number,
): [number, number] {
  const startPercentage = Math.max(
    (selectionInPixel[0].relative.x * 100) / width,
    0,
  );
  const endPercentage = (selectionInPixel[1].relative.x * 100) / width;

  return [startPercentage, endPercentage];
}
